using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class ServerTools
{
    [McpServerTool, Description("Greets a user by name.")]
    public static string Greet(
        [Description("The name to greet")] string name)
    {
        return $"Hello, {name}! Welcome to the MCP HTTP server.";
    }

    [McpServerTool, Description("Adds two numbers together.")]
    public static double Add(
        [Description("First number")] double a,
        [Description("Second number")] double b)
    {
        return a + b;
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerResourceType]
public static class ServerResources
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxConnections = 100,
            Features = new { EnableCache = true, EnableLogging = true }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/status", Name = "Server Status",
        MimeType = "application/json"),
     Description("Returns current server status information")]
    public static string GetServerStatus()
    {
        var status = new
        {
            Uptime = Environment.TickCount64 / 1000,
            MachineName = Environment.MachineName,
            ProcessorCount = Environment.ProcessorCount,
            Timestamp = DateTime.UtcNow
        };

        return JsonSerializer.Serialize(status, new JsonSerializerOptions { WriteIndented = true });
    }
}

